namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public string Ingredients { get; set; } = "";
    public string Steps { get; set; } = "";
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new() { Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Baguette, tomatoes, basil, garlic, olive oil", Steps = "1. Slice and toast bread\n2. Dice tomatoes with basil and garlic\n3. Top bread with tomato mixture\n4. Drizzle with olive oil" },
        new() { Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Button mushrooms, cream cheese, garlic, breadcrumbs, parsley", Steps = "1. Remove mushroom stems\n2. Mix cream cheese, garlic, and breadcrumbs\n3. Fill mushroom caps\n4. Bake at 375°F for 20 minutes" },
        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Spaghetti, eggs, pancetta, parmesan, black pepper", Steps = "1. Cook pasta al dente\n2. Fry pancetta until crisp\n3. Whisk eggs with parmesan\n4. Toss hot pasta with pancetta, then egg mixture\n5. Season with black pepper" },
        new() { Id = 4, Title = "Chicken Stir Fry", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Chicken breast, bell peppers, soy sauce, ginger, garlic, rice", Steps = "1. Slice chicken and vegetables\n2. Stir-fry chicken until golden\n3. Add vegetables and sauce\n4. Serve over steamed rice" },
        new() { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Dark chocolate, butter, eggs, sugar, flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold in flour and chocolate mixture\n4. Bake at 425°F for 12 minutes" },
        new() { Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Ladyfingers, mascarpone, espresso, cocoa, eggs, sugar", Steps = "1. Brew espresso and let cool\n2. Whisk egg yolks with sugar, fold in mascarpone\n3. Dip ladyfingers in espresso\n4. Layer with mascarpone mixture\n5. Dust with cocoa and refrigerate 4 hours" },
        new() { Id = 7, Title = "Mango Smoothie", Category = "Beverages", CategorySlug = "beverages", Ingredients = "Mango, yogurt, honey, ice", Steps = "1. Peel and dice mango\n2. Blend all ingredients until smooth\n3. Serve immediately" },
        new() { Id = 8, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking", Ingredients = "Bread flour, sourdough starter, salt, water", Steps = "1. Mix flour, water, and starter\n2. Add salt, knead 10 minutes\n3. Bulk ferment 4-6 hours\n4. Shape and proof overnight\n5. Bake in Dutch oven at 450°F" },
        new() { Id = 9, Title = "Vegetable Curry", Category = "Vegetarian", CategorySlug = "vegetarian", Ingredients = "Chickpeas, coconut milk, spinach, curry paste, rice", Steps = "1. Sauté curry paste in oil\n2. Add coconut milk and chickpeas\n3. Simmer 15 minutes\n4. Stir in spinach\n5. Serve over rice" },
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public string GetCategoryName(string slug)
    {
        return _recipes.FirstOrDefault(r => r.CategorySlug == slug)?.Category ?? slug;
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();
        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe != null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        var slug = category.ToLower().Replace(" ", "-");
        _recipes.Add(new Recipe
        {
            Id = _recipes.Max(r => r.Id) + 1,
            Title = title,
            Category = category,
            CategorySlug = slug,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

@page "/recipes/{CategorySlug}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@categoryName - RecipeShare</PageTitle>

<h1>@categoryName</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link">← Back to Categories</a>

@code {
    [Parameter]
    public string CategorySlug { get; set; } = "";

    private List<RecipeShare.Services.Recipe> recipes = new();
    private string categoryName = "";

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategorySlug);
        categoryName = RecipeService.GetCategoryName(CategorySlug);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeShare</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <PageTitle>@recipe.Title - RecipeShare</PageTitle>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[3..];
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[4..];
            <li>@text.Trim()</li>
        }
    </ol>

    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <a href="/recipes/@recipe.CategorySlug" class="btn btn-link mt-3">← Back to @recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Services.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe has been submitted successfully.
    </div>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="model.Ingredients" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(model.Title, model.Category, model.Ingredients, model.Steps);
        submitted = true;
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Services;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = "";

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = "";

    [Required(ErrorMessage = "Please list the ingredients.")]
    public string Ingredients { get; set; } = "";

    [Required(ErrorMessage = "Please describe the steps.")]
    public string Steps { get; set; } = "";
}

@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ffc107;
        transition: transform 0.1s;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
    .star-rating .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;
    private bool hasRated;

    private void Rate(int stars)
    {
        currentRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

