{"path": "/tmp/sv-210c5ab7f4b541c39b6c4abb03437b92/RecipeShare/Components/Pages/RecipePage.razor", "file_text": "@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeShare</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <PageTitle>@recipe.Title - RecipeShare</PageTitle>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[3..];
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[4..];
            <li>@text.Trim()</li>
        }
    </ol>

    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <a href="/recipes/@recipe.CategorySlug" class="btn btn-link mt-3">← Back to @recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Services.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}
"}

{"path": "/tmp/sv-210c5ab7f4b541c39b6c4abb03437b92/RecipeShare/Components/Pages/SubmitRecipe.razor", "file_text": "@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe has been submitted successfully.
    </div>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="model.Ingredients" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(model.Title, model.Category, model.Ingredients, model.Steps);
        submitted = true;
    }
}
"}

