+    public double AverageRating { get; set; }
+    public int RatingCount { get; set; }
+}
+
+public class RecipeService
+{
+    private readonly List<Recipe> _recipes = new()
+    {
+        new() { Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Baguette, tomatoes, basil, garlic, olive oil", Steps = "1. Slice and toast bread\n2. Dice tomatoes with basil and garlic\n3. Top bread with tomato mixture\n4. Drizzle with olive oil" },
+        new() { Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers", Ingredients = "Button mushrooms, cream cheese, garlic, breadcrumbs, parsley", Steps = "1. Remove mushroom stems\n2. Mix cream cheese, garlic, and breadcrumbs\n3. Fill mushroom caps\n4. Bake at 375°F for 20 minutes" },
+        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Spaghetti, eggs, pancetta, parmesan, black pepper", Steps = "1. Cook pasta al dente\n2. Fry pancetta until crisp\n3. Whisk eggs with parmesan\n4. Toss hot pasta with pancetta, then egg mixture\n5. Season with black pepper" },
+        new() { Id = 4, Title = "Chicken Stir Fry", Category = "Main Courses", CategorySlug = "main-courses", Ingredients = "Chicken breast, bell peppers, soy sauce, ginger, garlic, rice", Steps = "1. Slice chicken and vegetables\n2. Stir-fry chicken until golden\n3. Add vegetables and sauce\n4. Serve over steamed rice" },
+        new() { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Dark chocolate, butter, eggs, sugar, flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold in flour and chocolate mixture\n4. Bake at 425°F for 12 minutes" },
+        new() { Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts", Ingredients = "Ladyfingers, mascarpone, espresso, cocoa, eggs, sugar", Steps = "1. Brew espresso and let cool\n2. Whisk egg yolks with sugar, fold in mascarpone\n3. Dip ladyfingers in espresso\n4. Layer with mascarpone mixture\n5. Dust with cocoa and refrigerate 4 hours" },
+        new() { Id = 7, Title = "Mango Smoothie", Category = "Beverages", CategorySlug = "beverages", Ingredients = "Mango, yogurt, honey, ice", Steps = "1. Peel and dice mango\n2. Blend all ingredients until smooth\n3. Serve immediately" },
+        new() { Id = 8, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking", Ingredients = "Bread flour, sourdough starter, salt, water", Steps = "1. Mix flour, water, and starter\n2. Add salt, knead 10 minutes\n3. Bulk ferment 4-6 hours\n4. Shape and proof overnight\n5. Bake in Dutch oven at 450°F" },
+        new() { Id = 9, Title = "Vegetable Curry", Category = "Vegetarian", CategorySlug = "vegetarian", Ingredients = "Chickpeas, coconut milk, spinach, curry paste, rice", Steps = "1. Sauté curry paste in oil\n2. Add coconut milk and chickpeas\n3. Simmer 15 minutes\n4. Stir in spinach\n5. Serve over rice" },
+    };
+
+    private readonly Dictionary<int, List<int>> _ratings = new();
+
+    public List<Recipe> GetByCategory(string categorySlug)
+    {
+        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
+    }
+
+    public Recipe? GetById(int id)
+    {
+        return _recipes.FirstOrDefault(r => r.Id == id);
+    }
+
+    public string GetCategoryName(string slug)
+    {
+        return _recipes.FirstOrDefault(r => r.CategorySlug == slug)?.Category ?? slug;
+    }
+
+    public void AddRating(int recipeId, int stars)
+    {
+        if (stars < 1 || stars > 5) return;
+        if (!_ratings.ContainsKey(recipeId))
+            _ratings[recipeId] = new List<int>();
+        _ratings[recipeId].Add(stars);
+
+        var recipe = GetById(recipeId);
+        if (recipe != null)
+        {
+            recipe.RatingCount = _ratings[recipeId].Count;
+            recipe.AverageRating = _ratings[recipeId].Average();
+        }
+    }
+
+    public void AddRecipe(string title, string category, string ingredients, string steps)
+    {
+        var slug = category.ToLower().Replace(" ", "-");
+        _recipes.Add(new Recipe
+        {
+            Id = _recipes.Max(r => r.Id) + 1,
+            Title = title,
+            Category = category,
+            CategorySlug = slug,
+            Ingredients = ingredients,
+            Steps = steps
+        });
+    }
+}
+

