@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ffc107;
        transition: transform 0.1s;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
    .star-rating .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;
    private bool hasRated;

    private void Rate(int stars)
    {
        currentRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

